     6→
     7→// Project imports:
     8→import 'package:baseball_detector_flutter/controllers/user_accessible_contents_controller.dart';
     9→import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
    10→import 'package:baseball_detector_flutter/data/models/user_info.dart';
    11→import 'package:baseball_detector_flutter/data/result.dart';
    12→
    13→/// Executes an API call with an automatic retry mechanism on 422 errors.
    14→///
    15→/// This helper function is designed to handle cases where a user's permissions
    16→/// might be outdated on the client. When a 422 (Unprocessable Entity) error
    17→/// occurs, it automatically refreshes the user's accessible contents and retries
    18→/// the API call if the relevant permission has changed.
    19→///
    20→/// Type Parameters:
    21→/// - `T`: The expected success type of the API call's [Result].
    22→/// - `P`: The type of the permission value being checked (e.g., `bool` for a flag).
    23→///
    24→/// Parameters:
    25→/// - `ref`: The riverpod `Ref` to access providers.
    26→/// - `getPermissionValue`: A function that extracts the specific permission value
    27→///   (e.g., `isTeamCrossing`) from the [UserAccessibleContents].
    28→/// - `apiCall`: The actual API call to be executed. It receives the permission
    29→///   value as a parameter.
    30→///
    31→/// Returns:
    32→/// A [Future] that completes with the [Result] of the API call. It will be
    33→/// the result of the second call if a retry was performed.
    34→Future<Result<Failure, T>> executeWithPermissionRetry<T>({
    35→  required Ref ref,
    36→  required Future<Result<Failure, T>> Function() apiCall,
    37→}) async {
    38→  // Perform the first API call
    39→  var result = await apiCall();
