/// {@category Utils}
library;

// Package imports:
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/user_accessible_contents_controller.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/models/user_info.dart';
import 'package:baseball_detector_flutter/data/result.dart';

/// Executes an API call with an automatic retry mechanism on 422 errors.
///
/// This helper function is designed to handle cases where a user's permissions
/// might be outdated on the client. When a 422 (Unprocessable Entity) error
/// occurs, it automatically refreshes the user's accessible contents and retries
/// the API call if the relevant permission has changed.
///
/// Type Parameters:
/// - `T`: The expected success type of the API call's [Result].
/// - `P`: The type of the permission value being checked (e.g., `bool` for a flag).
///
/// Parameters:
/// - `ref`: The riverpod `Ref` to access providers.
/// - `getPermissionValue`: A function that extracts the specific permission value
///   (e.g., `isTeamCrossing`) from the [UserAccessibleContents].
/// - `apiCall`: The actual API call to be executed. It receives the permission
///   value as a parameter.
///
/// Returns:
/// A [Future] that completes with the [Result] of the API call. It will be
/// the result of the second call if a retry was performed.
Future<Result<Failure, T>> executeWithPermissionRetry<T, P>({
  required Ref ref,
  required P Function(UserAccessibleContents? contents) getPermissionValue,
  required Future<Result<Failure, T>> Function(P permission) apiCall,
}) async {
  // Get the initial permission value from the current state
  final initialContents = ref.read(userAccessibleContentsControllerProvider);
  final initialPermission = getPermissionValue(initialContents);

  // Perform the first API call
  var result = await apiCall(initialPermission);

  // If a 422 error occurs, try to refresh permissions and retry
  if (result.hasLeft && result.left is UnprocessableEntityFailure) {
    final updatedContents = await ref
        .read(userAccessibleContentsControllerProvider.notifier)
        .refresh();
    final updatedPermission = getPermissionValue(updatedContents);

    // Retry the API call only if the permission value has actually changed
    if (updatedPermission != initialPermission) {
      result = await apiCall(updatedPermission);
    }
  }

  return result;
}

