      expect(sessionJson['resources'], resourcesNull);

      final deserializedSession = Session.fromJson(sessionJson);
      expect(deserializedSession, session);
    });

    test('toJson3 (API)', () {
      final session = Session(
        id: id,
        userId: userId,
        playerId: playerId,
        location: location,
        note: note,
