    description: 'Test description',
    type: 1,
    maxBalls: 1000,
    isPaid: false,
    isActive: false,
    createdAt: createdAt,
    updatedAt: updatedAt,
    platformConfig: null,
  );
  final defaultTeamPlan = TeamPlan(
    id: id,
    teamId: teamId,
    planId: planId,
    startDate: startDate,
    endDate: endDate,
    currentUsage: currentUsage,
    isActive: isActive,
